import { _decorator, Component, director, Node, Label, Button, ProgressBar, Sprite } from 'cc';
import { GameManager } from '../Core/GameManager';
import { SceneConfig } from '../Config/SceneConfig';

const { ccclass, property } = _decorator;

@ccclass('DomainScene')
export class DomainScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    exploreBtn: Button = null;
    
    @property(Button)
    bossBtn: Button = null;
    
    @property(Label)
    domainNameLabel: Label = null;
    
    @property(Label)
    domainDescLabel: Label = null;
    
    @property(Label)
    bossNameLabel: Label = null;
    
    @property(Label)
    bossElementLabel: Label = null;
    
    @property(Label)
    rewardLabel: Label = null;
    
    @property(ProgressBar)
    explorationProgress: ProgressBar = null;
    
    private currentDomain: any = null;
    private explorationValue: number = 0;
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.exploreBtn.node.on(Button.EventType.CLICK, this.onExplore, this);
        this.bossBtn.node.on(Button.EventType.CLICK, this.onChallengeBoss, this);
    }
    
    start() {
        // 从GameManager获取当前选中的财域
        this.currentDomain = SceneConfig.domains['zishi']; // 默认子时
        
        this.updateUI();
    }
    
    updateUI() {
        if (!this.currentDomain) return;
        
        this.domainNameLabel.string = this.currentDomain.name;
        this.domainDescLabel.string = this.currentDomain.desc;
        this.bossNameLabel.string = `BOSS: ${this.currentDomain.boss.name}`;
        this.bossElementLabel.string = `属性: ${this.currentDomain.boss.element}`;
        this.rewardLabel.string = `奖励: ${this.currentDomain.boss.reward}`;
        
        this.explorationProgress.progress = this.explorationValue;
    }
    
    onExplore() {
        // 探索逻辑
        GameManager.getInstance().showLoading('探索中...');
        
        setTimeout(() => {
            GameManager.getInstance().hideLoading();
            
            // 增加探索度
            this.explorationValue = Math.min(1, this.explorationValue + 0.1);
            this.explorationProgress.progress = this.explorationValue;
            
            // 随机奖励
            const reward = Math.floor(Math.random() * 100) + 50;
            GameManager.getInstance().playerData.addCurrency('incense_money', reward);
            
            // 显示奖励
            console.log(`探索获得${reward}香火钱`);
            
            // 检查是否触发战斗
            if (Math.random() < 0.3) {
                director.loadScene('BattleScene');
            }
        }, 1000);
    }
    
    onChallengeBoss() {
        if (this.explorationValue < 1) {
            console.log('需要100%探索度才能挑战BOSS');
            return;
        }
        
        // 进入BOSS战
        director.loadScene('BossScene');
    }
    
    onBack() {
        director.loadScene('MapScene');
    }
}
